import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import * as api from '../../utils/api';

const GraphViz = ({ highlightPath = [] }) => {
  const svgRef = useRef();
  const [edges, setEdges] = useState([]);
  const [hospitals, setHospitals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [tooltip, setTooltip] = useState(null);

  useEffect(() => {
    Promise.all([api.getGraphEdges(), api.getHospitals()])
      .then(([edgesRes, hospitalsRes]) => {
        setEdges(edgesRes.data.data);
        setHospitals(hospitalsRes.data.data);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (!edges.length || !hospitals.length) return;
    drawGraph();
  }, [edges, hospitals, highlightPath]);

  const drawGraph = () => {
    const container = svgRef.current?.parentElement;
    if (!container) return;
    const W = container.clientWidth || 800;
    const H = 520;

    d3.select(svgRef.current).selectAll('*').remove();

    const svg = d3.select(svgRef.current)
      .attr('width', W)
      .attr('height', H);

    // Gradient definitions
    const defs = svg.append('defs');
    const glow = defs.append('filter').attr('id', 'glow');
    glow.append('feGaussianBlur').attr('stdDeviation', '3').attr('result', 'coloredBlur');
    const feMerge = glow.append('feMerge');
    feMerge.append('feMergeNode').attr('in', 'coloredBlur');
    feMerge.append('feMergeNode').attr('in', 'SourceGraphic');

    // Background
    svg.append('rect').attr('width', W).attr('height', H).attr('fill', '#0a1628');

    // Nodes and links
    const nodeMap = new Map(hospitals.map((h) => [h.nodeId, h]));
    const seen = new Set();
    const links = edges
      .filter((e) => {
        const key = [e.fromNodeId, e.toNodeId].sort().join('-');
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      })
      .map((e) => ({
        source: e.fromNodeId,
        target: e.toNodeId,
        distance: e.distanceKm,
        time: e.travelTimeMinutes,
      }));

    const nodes = Array.from(new Set(edges.flatMap((e) => [e.fromNodeId, e.toNodeId])))
      .map((id) => ({ id, ...nodeMap.get(id) }));

    const highlightSet = new Set();
    for (let i = 0; i < highlightPath.length - 1; i++) {
      highlightSet.add([highlightPath[i], highlightPath[i + 1]].sort().join('-'));
    }

    const simulation = d3.forceSimulation(nodes)
      .force('link', d3.forceLink(links).id((d) => d.id).distance((d) => Math.min(d.distance * 8, 180)))
      .force('charge', d3.forceManyBody().strength(-400))
      .force('center', d3.forceCenter(W / 2, H / 2))
      .force('collision', d3.forceCollide(55));

    // Links
    const link = svg.append('g').selectAll('line').data(links).join('line')
      .attr('stroke', (d) => {
        const key = [d.source.id || d.source, d.target.id || d.target].sort().join('-');
        return highlightSet.has(key) ? '#f59e0b' : 'rgba(0, 196, 180, 0.25)';
      })
      .attr('stroke-width', (d) => {
        const key = [d.source.id || d.source, d.target.id || d.target].sort().join('-');
        return highlightSet.has(key) ? 3 : 1.5;
      })
      .attr('filter', (d) => {
        const key = [d.source.id || d.source, d.target.id || d.target].sort().join('-');
        return highlightSet.has(key) ? 'url(#glow)' : '';
      });

    // Link labels
    const linkLabel = svg.append('g').selectAll('text').data(links).join('text')
      .attr('fill', 'rgba(148, 163, 184, 0.7)')
      .attr('font-size', 10)
      .attr('text-anchor', 'middle')
      .text((d) => `${d.distance}km`);

    // Node groups
    const node = svg.append('g').selectAll('g').data(nodes).join('g')
      .call(d3.drag()
        .on('start', (e, d) => { if (!e.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on('drag', (e, d) => { d.fx = e.x; d.fy = e.y; })
        .on('end', (e, d) => { if (!e.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; })
      )
      .on('mouseenter', (e, d) => {
        setTooltip({ hospital: d, x: e.clientX, y: e.clientY });
      })
      .on('mouseleave', () => setTooltip(null));

    // Node circle
    node.append('circle')
      .attr('r', (d) => highlightPath.includes(d.id) ? 22 : 18)
      .attr('fill', (d) => {
        if (highlightPath.includes(d.id)) return '#f59e0b';
        if (d.beds?.available > 50) return 'rgba(16, 185, 129, 0.8)';
        if (d.beds?.available > 10) return 'rgba(0, 196, 180, 0.8)';
        return 'rgba(239, 68, 68, 0.7)';
      })
      .attr('stroke', (d) => highlightPath.includes(d.id) ? '#fff' : 'rgba(255,255,255,0.2)')
      .attr('stroke-width', 2)
      .attr('filter', (d) => highlightPath.includes(d.id) ? 'url(#glow)' : '');

    // Node label
    node.append('text')
      .attr('dy', 32)
      .attr('text-anchor', 'middle')
      .attr('fill', '#f8fafc')
      .attr('font-size', 11)
      .attr('font-weight', 500)
      .text((d) => d.name?.split(' ').slice(0, 2).join(' ') || d.id);

    // Available beds label inside circle
    node.append('text')
      .attr('dy', 4)
      .attr('text-anchor', 'middle')
      .attr('fill', 'white')
      .attr('font-size', 10)
      .attr('font-weight', 700)
      .text((d) => d.beds?.available ?? '?');

    simulation.on('tick', () => {
      link
        .attr('x1', (d) => d.source.x)
        .attr('y1', (d) => d.source.y)
        .attr('x2', (d) => d.target.x)
        .attr('y2', (d) => d.target.y);

      linkLabel
        .attr('x', (d) => (d.source.x + d.target.x) / 2)
        .attr('y', (d) => (d.source.y + d.target.y) / 2 - 5);

      node.attr('transform', (d) => `translate(${d.x},${d.y})`);
    });
  };

  if (loading) return (
    <div className="loading-center">
      <div className="spinner" />
    </div>
  );

  return (
    <div style={{ position: 'relative' }}>
      {/* Legend */}
      <div style={{ display: 'flex', gap: 20, marginBottom: 12, flexWrap: 'wrap' }}>
        {[
          { color: '#10b981', label: 'High availability (>50 beds)' },
          { color: '#00c4b4', label: 'Medium availability' },
          { color: '#ef4444', label: 'Low availability' },
          { color: '#f59e0b', label: 'Shortest path' },
        ].map(({ color, label }) => (
          <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 10, height: 10, borderRadius: '50%', background: color }} />
            <span style={{ fontSize: 12, color: 'var(--slate)' }}>{label}</span>
          </div>
        ))}
        <span style={{ fontSize: 12, color: 'var(--slate)' }}>• Numbers inside = available beds • Drag to rearrange</span>
      </div>

      <svg ref={svgRef} style={{ borderRadius: 12, border: '1px solid var(--border)', display: 'block', width: '100%' }} />

      {/* Tooltip */}
      {tooltip && (
        <div style={{
          position: 'fixed',
          left: tooltip.x + 12, top: tooltip.y - 60,
          background: 'var(--navy-light)',
          border: '1px solid var(--border)',
          borderRadius: 8, padding: '10px 14px',
          pointerEvents: 'none', zIndex: 999,
          boxShadow: 'var(--shadow)',
          minWidth: 200,
        }}>
          <div style={{ fontWeight: 600, marginBottom: 4 }}>{tooltip.hospital.name}</div>
          <div style={{ fontSize: 12, color: 'var(--slate)' }}>{tooltip.hospital.location?.city}</div>
          <div style={{ fontSize: 12, marginTop: 6 }}>
            <span style={{ color: 'var(--green)' }}>Available: {tooltip.hospital.beds?.available}</span>
            {' / '}
            <span style={{ color: 'var(--slate)' }}>Total: {tooltip.hospital.beds?.total}</span>
          </div>
          <div style={{ fontSize: 12, color: 'var(--teal)', marginTop: 2 }}>
            OPD: ₹{tooltip.hospital.fees?.opd} | ICU: ₹{tooltip.hospital.fees?.icu}/day
          </div>
        </div>
      )}
    </div>
  );
};

export default GraphViz;
